import React, { useState } from 'react';
import { cards, Card } from '../data/cards';
import PopupModal from './PopupModal';
import styles from './GridCards.module.css';

const GridCards: React.FC = () => {
  const [selectedCard, setSelectedCard] = useState<Card | null>(null);
  const [activeTab, setActiveTab] = useState<'code' | 'style'>('code');

  const openModal = (card: Card) => {
    setSelectedCard(card);
    setActiveTab('code');
  };

  const closeModal = () => {
    setSelectedCard(null);
  };

  return (
    <div className={styles.container}>
      <div className={styles.grid}>
        {cards.map((card) => (
          <div key={card.id} className={styles.card} onClick={() => openModal(card)}>

            <div className={styles.preview}>{card.component}</div>
            <div className={styles.body}>
              <h3 className={styles.title}>{card.title}</h3>
            </div>
          </div>
        ))}
      </div>

      {selectedCard && (
        <div
          style={{
            position: 'fixed',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            backgroundColor: 'rgba(245, 247, 251, 0.9)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            zIndex: 1000,
          }}
          onClick={closeModal}
        >
          <div
            style={{
              backgroundColor: '#ffffff',
              width: '90%',
              maxWidth: '700px',
              maxHeight: '90%',
              overflow: 'auto',
              border: '1px solid rgba(40, 44, 52, 0.16)',
              boxShadow: '0 16px 40px rgba(40, 44, 52, 0.12)',
            }}
            onClick={(e) => e.stopPropagation()}
          >
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '30px 30px 20px 30px', borderBottom: '1px solid rgba(40, 44, 52, 0.12)', backgroundColor: '#f7f7f7' }}>
              <h2 style={{ margin: 0, fontSize: '24px', fontWeight: '400', color: '#282c34' }}>{selectedCard.title}</h2>
              <button onClick={closeModal} style={{ background: 'none', border: 'none', fontSize: '24px', cursor: 'pointer', color: '#282c34', padding: '5px' }}>×</button>
            </div>
            <div style={{ display: 'flex', padding: '0 30px', borderBottom: '1px solid rgba(40, 44, 52, 0.12)', backgroundColor: '#f7f7f7' }}>
              <button
                onClick={() => setActiveTab('code')}
                style={{
                  padding: '15px 25px',
                  border: 'none',
                  backgroundColor: activeTab === 'code' ? '#61dafb' : 'transparent',
                  color: activeTab === 'code' ? '#282c34' : '#666',
                  cursor: 'pointer',
                  fontSize: '16px',
                  fontWeight: '500',
                  borderBottom: activeTab === 'code' ? '3px solid #282c34' : 'none',
                }}
              >
                JavaScript
              </button>
              <button
                onClick={() => setActiveTab('style')}
                style={{
                  padding: '15px 25px',
                  border: 'none',
                  backgroundColor: activeTab === 'style' ? '#61dafb' : 'transparent',
                  color: activeTab === 'style' ? '#282c34' : '#666',
                  cursor: 'pointer',
                  fontSize: '16px',
                  fontWeight: '500',
                  borderBottom: activeTab === 'style' ? '3px solid #282c34' : 'none',
                }}
              >
                CSS
              </button>
            </div>
            <div style={{
              padding: '30px',
              fontFamily: 'Monaco, Menlo, "Ubuntu Mono", monospace',
              fontSize: '14px',
              lineHeight: '1.5',
              backgroundColor: '#f7f7f7',
              color: '#282c34',
              overflow: 'auto'
            }}>
              <pre style={{ margin: 0, whiteSpace: 'pre-wrap' }}>
                <code style={{
                  color: '#282c34',
                }}>
                  {activeTab === 'code' ? selectedCard.code : selectedCard.style}
                </code>
              </pre>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default GridCards;